1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	const PERCENT_BASE = 100;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	interface Item {
15	  type: string;
16	  cursed?: boolean;
17	  enchantment?: number;
18	  material?: string;
19	}
20	
21	interface Step {
22	  op: string;
23	  items?: Item[];
24	}
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	const BLOCK_SIZE = 3;
32	const BLOCK_PREMIUM = 60;
33	const CURSE_SURCHARGE_PERCENT = 50;
34	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	
38	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
39	
40	const percentOf = (amount: number, percent: number): number =>
41	  (amount * percent) / PERCENT_BASE;
42	
43	const itemBasePremium = (item: Item): number => {
44	  const base = BASE_PREMIUM[item.type];
45	  const curse = item.cursed ? percentOf(base, CURSE_SURCHARGE_PERCENT) : 0;
46	  const highEnchantment =
47	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
48	      ? percentOf(base, HIGH_ENCHANTMENT_SURCHARGE_PERCENT)
49	      : 0;
50	  return base + curse + highEnchantment;
51	};
52	
53	const sumBase = (items: Item[]): number =>
54	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
55	
56	const partitionByType = (items: Item[]): Item[][] => {
57	  const groups: Record<string, Item[]> = {};
58	  items.forEach((item) => (groups[item.type] ??= []).push(item));
59	  return Object.values(groups);
60	};
61	
62	const priceGroup = (group: Item[]): number =>
63	  group.length === BLOCK_SIZE && isComponent(group[0])
64	    ? BLOCK_PREMIUM
65	    : sumBase(group);
66	
67	const sumBasePremiums = (items: Item[]): number =>
68	  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);
69	
70	const applyFirstInsuranceSurcharge = (base: number): number =>
71	  Math.ceil(base + percentOf(base, FIRST_INSURANCE_PERCENT));
72	
73	const quotePremium = (items: Item[]): number =>
74	  applyFirstInsuranceSurcharge(sumBasePremiums(items)) + PROCESSING_FEE;
75	
76	const executeStep = (step: Step): { premium: number } => ({
77	  premium: quotePremium(step.items ?? []),
78	});
79	
80	export const runScenario = (input: unknown): { results: unknown[] } => {
81	  const scenario = input as Scenario;
82	  return { results: scenario.steps.map(executeStep) };
83	};
